import Joi from 'joi';

const objectId = (value, helpers) => {
  if (!Joi.string().hex().length(24).validate(value).error) {
    return value;
  }
  return helpers.message('{{#label}} must be a valid mongo id');
};

const updateCardSchema = Joi.object({
  title: Joi.string().min(3).max(50).trim().strict(),
  description: Joi.string().max(5000).trim().strict().optional(),
  boardId: Joi.string().required().custom(objectId, 'custom objectId validation'),
  // Các trường khác có thể được thêm vào đây và cho phép optional
  // để API có thể cập nhật từng phần
  columnId: Joi.string().custom(objectId, 'custom objectId validation').optional()
});

export default updateCardSchema;
